const { Storage } = require('@google-cloud/storage');
const express = require('express');

// Create a client instance of the Google Cloud Storage service
const storage = new Storage();

// Initialize Express.js app
const app = express();
app.use(express.json());

// Define allowed buckets and files for security
const allowedBuckets = ['your-bucket-name'];
const allowedFiles = {};

// Function to validate input parameters
function validateInput(req, res, next) {
  const bucketName = req.query.bucket;
  const filePath = req.query.path;

  if (!bucketName || !filePath) {
    return res.status(400).send('Missing required query parameter');
  }

  if (allowedBuckets.indexOf(bucketName) === -1) {
    return res.status(403).send(`Bucket ${bucketName} not allowed`);
  }

  next();
}

// Function to get file from Cloud Storage
function getFile(req, res) {
  const bucketName = req.query.bucket;
  const filePath = req.query.path;

  storage.bucket(bucketName)
    .file(filePath)
    .createReadStream()
    .on('error', (err) => {
      console.error(err);
      res.status(404).send(`File not found: ${filePath}`);
    })
    .pipe(res);
}

// Define API endpoint for serving files
app.get('/serve/:bucket/:path*', validateInput, getFile);

// Export the app to be used by Cloud Functions
module.exports = { cloudFunction: app };

